6	import { writeFileSync, mkdirSync, existsSync } from 'fs';
7	import { join, dirname } from 'path';
8	import { fileURLToPath } from 'url';
9	import { createHash } from 'crypto';
10	
11	const __dirname = dirname(fileURLToPath(import.meta.url));
12	const IMAGES_DIR = join(__dirname, '..', 'images');
13	
14	/**
15	 * 提取当前会话消息中的所有图片 URL（带消息索引）
16	 * Returns Array<{url: string, messageIndex: number}>
17	 */
18	export async function extractImageUrls(frame) {
19	  return frame.evaluate(() => {
20	    const seen = new Set();
21	    const results = [];
22	    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
23	    wrappers.forEach((wrapper, idx) => {
24	      wrapper.querySelectorAll('img').forEach(img => {
25	        if (img.classList.contains('emotion')) return;
26	        const src = img.src || '';
27	        if (!src.startsWith('http') || seen.has(src)) return;
28	        // Skip chat platform emoji/smile images
29	        if (src.includes('atmgateway-client.alibaba.com/smily')) return;
30	        if (src.includes('clouddisk.alibaba.com')) return;
31	        // Skip tiny emoji images (72x72, 80x80 thumbnails with tps- pattern)
32	        if (/tps-\d+-\d+\.(png|webp)/.test(src) && (src.includes('tps-72-72') || src.includes('tps-80-80') || src.includes('tps-60-60') || src.includes('tps-48-48'))) return;
33	        seen.add(src);
34	        results.push({ url: img.src, messageIndex: idx });
35	      });
36	    });
37	    return results;
38	  });
39	}
