41	/**
42	 * 通过浏览器上下文下载图片（复用登录态 cookie）
43	 * 创建临时页面 -> 导航到图片URL -> 保存响应体 -> 关闭页面
44	 */
45	async function downloadImageViaContext(ctx, url, savePath) {
46	  const newPage = await ctx.newPage();
47	  try {
48	    const response = await newPage.goto(url, {
49	      waitUntil: 'load',
50	      timeout: 20000,
51	    });
52	    if (!response.ok()) {
53	      throw new Error(`HTTP ${response.status()}`);
54	    }
55	    const buffer = await response.body();
56	    writeFileSync(savePath, buffer);
57	    return buffer.length;
58	  } finally {
59	    await newPage.close();
60	  }
61	}
62	
63	/**
64	 * 为当前客户保存所有图片
65	 * @param {BrowserContext} ctx - Playwright 浏览器上下文（含登录态）
66	 * @param {object} frame - TM 聊天 iframe
67	 * @param {string} customerName - 客户名称（用于目录名）
68	 * @param {Set} globalDedup - 全局去重 Set（避免重复下载）
69	 * @param {Array} messages - 当前会话的消息数组（用于关联消息索引）
70	 * @returns {Promise<Array<{url: string, filePath: string, size: number, messageIndex: number}>>}
71	 */
72	export async function saveCustomerImages(ctx, frame, customerName, globalDedup, messages = []) {
73	  const imageEntries = await extractImageUrls(frame);
74	  if (imageEntries.length === 0) return [];
75	
76	  const dir = join(IMAGES_DIR, sanitizeName(customerName));
77	  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
78	
79	  // Build a map: DOM wrapper index → message index
80	  // The wrappers in DOM and messages array are aligned (both 0-indexed in order)
81	  const domToMsgIndex = new Map();
82	  for (const msg of messages) {
83	    if (msg.index !== undefined) {
84	      domToMsgIndex.set(msg.index, msg.index);
85	    }
86	  }
87	
88	  const saved = [];
89	  for (const { url, messageIndex: domIndex } of imageEntries) {
90	    if (globalDedup.has(url)) continue;
91	    globalDedup.add(url);
92	
93	    const ext = url.match(/\.(jpe?g|png|gif|webp|bmp)(?:[?#]|$)/i)?.[1] || 'jpg';
94	    const hash = createHash('md5').update(url).digest('hex').substring(0, 10);
95	    const filename = `${Date.now()}_${hash}.${ext}`;
96	    const filePath = join(dir, filename);
97	
98	    try {
99	      const size = await downloadImageViaContext(ctx, url, filePath);
100	      // Map DOM wrapper index to message array index
101	      const msgIndex = messages.findIndex(m => m.index === domIndex);
102	      saved.push({ url, filePath, size, messageIndex: msgIndex >= 0 ? msgIndex : domIndex });
103	    } catch (err) {
104	      console.log(`   ⚠️ 图片跳过: ${url.substring(0, 60)}… (${err.message})`);
105	    }
106	  }
107	  return saved;
108	}
109	
110	/**
111	 * 在每条消息中检测图片并注入 URL（带消息索引）
112	 */
113	export function extractMessageImages(frame) {
114	  return frame.evaluate(() => {
115	    const results = [];
116	    document.querySelectorAll('.message-item-wrapper.messenger').forEach((wrapper, idx) => {
117	      const imgs = wrapper.querySelectorAll('img');
118	      if (imgs.length === 0) return;
119	      const urls = Array.from(imgs)
120	        .map(img => img.src)
121	        .filter(s => s && s.startsWith('http'));
122	      if (urls.length > 0) results.push({ messageIndex: idx, urls });
123	    });
124	    return results;
125	  });
126	}
127	
128	/**
129	 * 提取当前会话消息中的文件链接（云盘/下载等）
130	 */
131	export async function extractFileUrls(frame) {
132	  return frame.evaluate(() => {
133	    const files = [];
134	    document.querySelectorAll('.message-item-wrapper.messenger').forEach((wrapper, idx) => {
135	      // 卡消息中的链接
136	      wrapper.querySelectorAll('a').forEach(a => {
137	        const href = a.href || '';
138	        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
139	          files.push({
140	            url: href,
141	            name: (a.textContent || '').trim() || (a.title || ''),
142	            type: 'clouddisk',
143	            messageIndex: idx,
144	          });
145	        }
146	      });
147	      // Also check img src for cloud disk file links
148	      wrapper.querySelectorAll('img').forEach(img => {
149	        const src = img.src || '';
150	        if (src.includes('clouddisk.alibaba.com') && !files.some(f => f.url === src)) {
151	          files.push({
152	            url: src,
153	            name: (img.alt || img.title || ''),
154	            type: 'clouddisk',
155	            messageIndex: idx,
156	          });
157	        }
158	      });
159	      // 文件类元素的文本内容
160	      const cardText = wrapper.querySelector('.session-rich-content.card');
161	      if (cardText) {
162	        const text = cardText.textContent || '';
163	        if (/\.(pdf|docx?|xlsx?|pptx?|zip|rar|jpg|png)\b/i.test(text) && !files.some(f => f.text === text)) {
164	          files.push({ url: '', name: text.substring(0, 100), type: 'card_reference', messageIndex: idx });
165	        }
166	      }
167	    });
168	    return files;
169	  });
170	}
171	
172	function sanitizeName(name) {
173	  return name.replace(/[/\\?%*:|"<>]/g, '_').substring(0, 60);
174	}
