158	        }
159	        const cardImg = cardEl.querySelector('img');
160	        if (cardImg && cardImg.src && cardImg.src.startsWith('http')) {
161	          if (!cardData) cardData = {};
162	          cardData.imageUrl = cardImg.src;
163	        }
164	      }
165	
166	      messages.push({
167	        index,
168	        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
169	        content,
170	        messageType,
171	        timestamp,
172	        sender: sender || undefined,
173	        isCard: !!cardEl,
174	        cardData,
175	        emojis: emojis.length > 0 ? emojis : undefined,
176	        hasImages,
177	        fileLinks: fileLinks.length > 0 ? fileLinks : undefined,
178	        isAutoReply: autoReply.includes('自动接待发送') || autoReply.includes('去优化'),
179	        isSystem,
180	      });
181	    });
182	
183	    return messages;
184	  });
