191	async function scrollChatToLoadAll(frame, { maxScrolls = 60, stableThreshold = 3 } = {}) {
192	  const containerInfo = await frame.evaluate(() => {
193	    // Try common scroll container selectors
194	    const selectors = [
195	      '.message-list-container',
196	      '.chat-list',
197	      '.im-chat-list',
198	      '.message-list',
199	      '[class*="message-list"]',
200	      '[class*="chat-list"]',
201	      '[class*="chat-content"]',
202	      '.session-message-list-wrapper',
203	    ];
204	    for (const sel of selectors) {
205	      const el = document.querySelector(sel);
206	      if (el && el.scrollHeight > el.clientHeight) {
207	        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
208	      }
209	    }
210	    // Fallback: find any scrollable element containing messages
211	    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
212	    if (wrappers.length > 0) {
213	      let el = wrappers[0].parentElement;
214	      while (el) {
215	        if (el.scrollHeight > el.clientHeight) {
216	          return { selector: null, found: true, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
217	        }
218	        el = el.parentElement;
219	      }
220	    }
221	    return null;
222	  });
223	
224	  if (!containerInfo) {
225	    console.log('   ⚠️ 未找到可滚动容器，使用当前渲染消息');
226	    return 0;
227	  }
228	
229	  console.log(`   📜 滚动加载历史消息... (容器: ${containerInfo.selector || '自动检测'})`);
230	
231	  let prevCount = 0;
232	  let stableCount = 0;
233	  let totalScrolled = 0;
234	
235	  for (let i = 0; i < maxScrolls; i++) {
236	    const { count, scrolled } = await frame.evaluate(({ selector, containerInfo: ci }) => {
237	      // Find scroll container
238	      let container = null;
239	      if (selector) {
240	        container = document.querySelector(selector);
241	      } else {
242	        const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
243	        if (wrappers.length > 0) {
244	          let el = wrappers[0].parentElement;
245	          while (el) {
246	            if (el.scrollHeight > el.clientHeight) { container = el; break; }
247	            el = el.parentElement;
248	          }
249	        }
250	      }
251	      if (!container) return { count: 0, scrolled: false };
252	
253	      const oldScrollTop = container.scrollTop;
254	      // Scroll to top to trigger loading of older messages
255	      container.scrollTop = 0;
256	      const scrolled = oldScrollTop > 0;
257	      return {
258	        count: document.querySelectorAll('.message-item-wrapper.messenger').length,
259	        scrolled,
260	      };
261	    }, { selector: containerInfo.selector, containerInfo });
262	
263	    totalScrolled++;
264	
265	    if (scrolled) {
266	      // Wait for virtual scroll to render new items
267	      await new Promise(r => setTimeout(r, 800));
268	    }
269	
270	    const newCount = await frame.evaluate(() =>
271	      document.querySelectorAll('.message-item-wrapper.messenger').length
272	    );
273	
274	    if (newCount === prevCount) {
275	      stableCount++;
276	      if (stableCount >= stableThreshold) break;
277	    } else {
278	      stableCount = 0;
279	      console.log(`      ${prevCount} → ${newCount} 条消息`);
280	    }
281	    prevCount = newCount;
282	
283	    if (!scrolled) break;
284	  }
285	
286	  console.log(`   ✅ 共加载 ${prevCount} 条消息 (滚动 ${totalScrolled} 次)`);
287	  return prevCount;
288	}
