64	async function parseMailList(page) {
65	  return page.evaluate(() => {
66	    const items = document.querySelectorAll('.plain-list-item');
67	    return Array.from(items).map((item, idx) => {
68	      const walker = document.createTreeWalker(item, NodeFilter.SHOW_TEXT, null);
69	      const nodes = [];
70	      while (walker.nextNode()) {
71	        const t = walker.currentNode.textContent.trim();
72	        if (!t) continue;
73	        const p = walker.currentNode.parentElement;
74	        const cls = p ? (typeof p.className === 'string' ? p.className : '') : '';
75	        nodes.push({ t, cls });
76	      }
77	      return {
78	        idx,
79	        senderName: nodes[0]?.t || '',
80	        senderEmail: nodes[1]?.t || '',
81	        subject: nodes.find(n => n.cls.includes('subject'))?.t || '',
82	        preview: nodes.filter(n => n.cls === 'ellipsis').map(n => n.t).join(' ') || '',
83	        time: nodes.find(n => n.cls.includes('time'))?.t || '',
84	      };
85	    });
86	  });
87	}
