135	async function getMailDetail(page, ctx) {
136	  return page.evaluate(() => {
137	    const iframe = document.querySelector('.mm-split-pane__right iframe');
138	    if (!iframe) return { bodyText: '', images: [], attachments: [] };
139	    try {
140	      const doc = iframe.contentDocument || iframe.contentWindow.document;
141	      if (!doc || !doc.body) return { bodyText: '', images: [], attachments: [] };
142	      const bodyText = doc.body.innerText || '';
143	      const images = Array.from(doc.querySelectorAll('img'))
144	        .filter(img => img.src && img.src.startsWith('http'))
145	        .map(img => ({ src: img.src, alt: img.alt || '' }));
146	      const attachments = Array.from(doc.querySelectorAll('a[href]'))
147	        .filter(a => /download|attach|aliyundoc/i.test(a.href))
148	        .map(a => ({ url: a.href, name: a.textContent.trim() }));
149	      return { bodyText, images, attachments };
150	    } catch {
151	      return { bodyText: '', images: [], attachments: [] };
152	    }
153	  });
154	}
