156	// ============================================================
157	// 保存邮件内图片
158	// ============================================================
159	async function saveMailImages(ctx, images) {
160	  const saved = [];
161	  for (const img of images) {
162	    if (img._saved) continue;
163	    img._saved = true;
164	    try {
165	      const ext = img.src.match(/\.(jpe?g|png|gif|webp)(?:[?#]|$)/i)?.[1] || 'jpg';
166	      const hash = createHash('md5').update(img.src).digest('hex').substring(0, 10);
167	      const filename = `${Date.now()}_${hash}.${ext}`;
168	      const filePath = join(MAIL_IMG_DIR, filename);
169	      const p = await ctx.newPage();
170	      try {
171	        const r = await p.goto(img.src, { waitUntil: 'load', timeout: 15000 });
172	        if (r && r.ok()) {
173	          const buf = await r.body();
174	          writeFileSync(filePath, buf);
175	          saved.push({ url: img.src, filePath, size: buf.length });
176	        }
177	      } finally {
178	        await p.close();
179	      }
180	    } catch {}
181	  }
182	  return saved;
183	}
