188	function isCustomerRelated(email, customerNames) {
189	  const text = (email.subject + ' ' + email.senderName + ' ' + email.preview).toLowerCase();
190	  return customerNames.some(name => {
191	    if (!name || name === 'User name') return false;
192	    const parts = name.toLowerCase().split(/\s+/).filter(Boolean);
193	    return parts.some(p => p.length > 2 && text.includes(p));
194	  });
195	}
