199	// ============================================================
200	function extractCustomerName(email, customerNames) {
201	  const text = email.subject + ' ' + email.preview;
202	  for (const name of customerNames) {
203	    if (!name || name === 'User name') continue;
204	    if (text.toLowerCase().includes(name.toLowerCase())) return name;
205	  }
206	  return null;
207	}
